class Solution:
    def minStartingIndex(self, s: str, pattern: str) -> int:
        def is_almost_equal(s: str, pattern: str) -> bool:
            diff_count = 0
            for i in range(len(pattern)):
                if s[i] != pattern[i]:
                    diff_count += 1
                if diff_count > 1:
                    return False
            return True

        min_index = -1
        for i in range(len(s) - len(pattern) + 1):
            if is_almost_equal(s[i:i + len(pattern)], pattern):
                return i
        return min_index
```
